@RestController
public class LogoutController {
    
    @Value("${app.allowed-redirects}")
    private List<String> allowedRedirects;
    
    @GetMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        // Invalidate session
        request.getSession().invalidate();
        
        // Get redirect URL from parameter
        String nextUrl = request.getParameter("next");
        
        // Validate redirect URL
        if (nextUrl != null && !nextUrl.isEmpty()) {
            if (isValidRedirectUrl(nextUrl)) {
                response.sendRedirect(nextUrl);
            } else {
                // Redirect to default page if invalid
                response.sendRedirect("/login");
            }
        } else {
            // Redirect to default page if no next parameter
            response.sendRedirect("/login");
        }
    }
    
    private boolean isValidRedirectUrl(String url) {
        try {
            URI uri = new URI(url);
            
            // Check if it's a relative path or absolute URL with allowed domain
            if (uri.isAbsolute()) {
                // For absolute URLs, check against allowed domains
                return allowedRedirects.stream()
                    .anyMatch(allowed -> url.startsWith(allowed));
            } else {
                // For relative paths, allow them
                return true;
            }
        } catch (URISyntaxException e) {
            return false;
        }
    }
}